var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"성황청 비밀 서고에는 수많은 <color=#ffd34c>기적</color>이 잠들어 있다.","JPN":"聖皇庁の秘密書庫には数多くの<color=#ffd34c>奇跡</color>が眠っている。","ENG":"Countless <color=#ffd34c>Miracles</color> lie dormant in the Holy Curia's secret library.","TWN":"聖皇廳秘密書庫中沉睡著無數<color=#ffd34c>奇蹟</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"관리국의 존재가 수면 위로 드러나기 전부터 교회가 수집해 온 기적의 실마리들.","JPN":"管理局の存在が明らかになる前から、教会が収集してきた奇跡の手がかり。","ENG":"They are clues that the church had been collecting long before the existence of the Administration was revealed to the public.","TWN":"在管理局的存在浮出水面之前，教會就已經收集了奇蹟的線索。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"이를테면, 소리 내어 읽은 것만으로도 배탈을 치료할 수 있다고 전해지는 마도서부터.","JPN":"たとえるなら、声に出して読んだだけでも腹痛を治癒することができると言われている魔導書から。","ENG":"For instance, there is a grimoire that can cure stomachaches just by reading its passages out loud.","TWN":"比如說，只要大聲朗讀就能治癒腹痛的魔法書。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"이를테면, 누명을 쓰고 새하얀 피를 흘리며 숨을 거둔 순교자의 유언장까지.","JPN":"濡れ衣を着せられて白色の血を流しながら息絶えた殉教者の遺言書まで。","ENG":"Or even the will of a martyr who died after being falsely accused and shedding pure white blood.","TWN":"再比如，背負冤屈，流著純白的血，臨終前的殉教者遺言。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"성황청 설립 이래로, 시성성은 수단과 방법을 가리지 않고 기적의 행방을 쫓아왔으며.","JPN":"聖皇庁の設立以来、列聖省は手段を択ばずに奇跡の行方を追跡し。","ENG":"Since the establishment of the Holy Curia, the Dicastery for the Causes of Saints has pursued the whereabouts of Miracles by any means possible.","TWN":"自聖皇廳成立以來，封聖部一直不擇手段地追尋奇蹟的蹤跡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"또한 그 기적에 경중은 없으니…….","JPN":"また、その奇跡に軽重はない……","ENG":"Moreover, no Miracle is weighed greater or lesser than another...","TWN":"而且那奇蹟沒有輕重之分……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"따라서 비밀 서고의 사서는 있는 그대로의 기적, 그 자체를 보존할 의무가 있다.","JPN":"よって、秘密書庫の司書はありのままの奇跡、それ自体を保存する義務がある。","ENG":"Therefore, the librarian of the secret library has a duty to preserve the Miracle itself.","TWN":"因此，秘密書庫的管理員有義務將這些奇蹟原原本本地保存下來。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_09"},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"때때로, 그 기적이 아무리 사소하고 보잘것없어 보일지라도.","JPN":"時にその奇跡がとても小さく些細なものに見えたとしても。","ENG":"At times, they may seem insignificant.","TWN":"有時候，那些奇蹟看起來微不足道。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"때때로, 그 기적이 세상에서 완전히 지워버리고 싶을 정도로 낯부끄러운 것일지라도.","JPN":"時にその奇跡がこの世から完全に消しさりたいほど不名誉なことであるとしても。","ENG":"At other times, they are embarrassing to the point one wishes to completely erase the Miracles from the world.","TWN":"有時候，那些奇蹟甚至會讓人羞愧到想要將其徹底從世界上抹去。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"주께서 사서에게 부여하신 의무는 기적의 보존이지, 결코 말소가 아닐 터.","JPN":"主が司書に与えられし義務は奇跡の保存であり、決して抹消ではない。","ENG":"Nevertheless, the duty given to the librarian by the Lord is to preserve, not destroy.","TWN":"但主賦予管理員的職責是保存奇蹟，絕不是抹除。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"그렇기에…….","JPN":"そのため……","ENG":"And so...","TWN":"正因為如此……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"subtitle","speaker":null,"text":{"KOREA":"성황청 시성성, 기적 심사 보고서\\n성무 코드 <color=#ffd34c>X12MAS25</color>","JPN":"聖皇庁の列聖省、奇跡審査報告書\\n聖務コード<color=#ffd34c>X12MAS25</color>","ENG":"Holy Curia Dicastery for the Causes, Miracle Evaluation Report\\nSacred Mission Code <color=#ffd34c>X12MAS25</color>","TWN":"聖皇廳封聖部, 奇蹟審查報告書\\n聖務代碼 <color=#ffd34c>X12MAS25</color>"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"subtitle","speaker":null,"text":{"KOREA":"X12MAS25는 집행사제 클로디아 넬슨이 성탄절을 축하하기 위해 제조한 케이크가 생명력을 획득.\\n현장에 있던 다수의 인원을 공격한 사건이다.","JPN":"X12MAS25は執行司祭クラウディア・ネルソンが聖誕祭を祝うために製造したケーキに\\n生命が宿り、現場にいた多数の人員を攻撃した事件である。","ENG":"X12MAS25. A cake made by Inquisitorial Priest Claudia Nelson to celebrate Christmas obtained life.\\nThis was a case where the cake attacked a number of individuals at the scene.","TWN":"X12MAS25是治理祭司克勞迪婭·尼爾森為慶祝聖誕節而製作的蛋糕獲得生命力量，\\n並攻擊現場的多數人員的事件。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"subtitle","speaker":null,"text":{"KOREA":"시성성 조사관이 현장을 조사한 결과,\\n케이크의 잔여물에서 이면세계의 성분들이 검출되었으나, 잔여 침식파는 검출되지 않아 인체에는 무해했다.","JPN":"列聖省の調査官が現場を調査した結果、\\nケーキの残骸から裏世界の成分が検出されたが、\\n残余侵食波は検出されず人体には無害であった。","ENG":"According to the investigation conducted by the Dicastery for the Causes inspector,\\ntraces of the elements from the Counterside were found in the cake residue.\\nHowever no residual Corruption rays were detected and deemed harmless to humans.","TWN":"封聖部監察官對現場進行調查結果，\\n在蛋糕的殘留物中檢測到異界成分，但未檢測到殘留的侵蝕波，因此對人體是無害的。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"subtitle","speaker":null,"text":{"KOREA":"또한 생명력을 획득한 케이크는 자아를 가지고 있었으며, 높은 지성을 보유하고 있었다는 진술을 확보할 수 있었다.","JPN":"また、生命が宿ったケーキは自我を持ち、\\n高い知性を保有していたという証言を確保した。","ENG":"Additionally, testimonies confirmed that the cake was sentient and displayed a high level of intelligence.","TWN":"此外，獲得生命力量的蛋糕不僅擁有自我意識，還被證實具有高度的智慧。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"subtitle","speaker":null,"text":{"KOREA":"위와 같은 사실에 근거.\\n조사관은 클로디아 넬슨이 제조한 케이크는 일반적인 침식현상과는 관련이 없다고 결론지었다.","JPN":"上記の事実に基づき。\\n調査官はクラウディア・ネルソンが製造したケーキは\\n一般的な侵食現象とは関係がないと結論づけた。","ENG":"Based on these findings,\\nthe inspector concluded that the cake made by Claudia Nelson is not related to a typical Counterside Effect.","TWN":"根據上述事實，\\n監察官得出結論，克勞迪婭·尼爾森製作的蛋糕與一般的侵蝕現象無關。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"subtitle","speaker":null,"text":{"KOREA":"이에 따라, 시성성은 이 사건을 초자연적 기적현상에 대한 단서로 판단.\\n케이크를 통하여 다른 차원의 존재를 불러내어 직접 소통할 수 있다는 가능성을 제시하였다.","JPN":"これにより、\\n列聖省はこの事件を超自然的な奇跡現象についての手がかりと判断。\\nケーキを媒介に他の次元の存在を呼び出し直接疎通できるという可能性を提示した。","ENG":"Accordingly, the Dicastery for the Causes classifies this incident as a potential clue to a supernatural Miracle.\\nThe cake of this incident suggests the possibility of summoning\\nand communicating with entities from other dimensions.","TWN":"因此，封聖部委員會認為這一事件是超自然奇蹟現象的線索。\\n透過蛋糕，透露出與另一個維度的存在進行直接溝通的可能性。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"subtitle","speaker":null,"text":{"KOREA":"보다 면밀한 조사를 위해, 제9호 기적심의회의 협조를 요구하는 바.\\n집행사제 비블리데 루체에게 X12MAS25에 대한 상세한 경위서와 해당 케이크 레시피의 제출을 요한다.","JPN":"より詳しい調査のため、第9号奇跡審議会の協力を要求する。\\n執行司祭ビブリデ・ルーチェにはX12MAS25についての詳細経緯書と、\\n該当のケーキレシピの提出を要する。","ENG":"To conduct a more thorough investigation, cooperation from the Miracle Investigation Council 9 is requested.\\nInquisitorial Priest Biblide Luce is asked to submit a detailed report regarding X12MAS25 along with the cake's recipe.","TWN":"為進行更詳細的調查，需要第九奇蹟議會的協助。\\n要求治理祭司布莉黛·露契提交關於X12MAS25的詳細經過報告以及相關蛋糕的食譜。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주여.","JPN":"主よ。","ENG":"Oh, Lord.","TWN":"主啊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신의 어린 양이 고해성사의 기도를 올립니다.","JPN":"子羊が告解の祈りを捧げます。","ENG":"I offer a prayer of confession.","TWN":"你的小羊正在懺悔祈禱。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"그렇기에 여기 한 젊은 사서가 고민에 빠졌다.","JPN":"そのためここに、1人の若い司書が悩んでいる。","ENG":"One young librarian finds herself in deep contemplation.","TWN":"因此，這裡有一位年輕的圖書管理員陷入了困境。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"그녀가 손에 넣은 것은 어느 디저트의 <color=#ffd34c>레시피</color>.","JPN":"彼女が手に入れたのは、あるデザートの<color=#ffd34c>レシピ</color>。","ENG":"She has in her hands a certain dessert <color=#ffd34c>recipe</color>.","TWN":"她得到的是某種甜點的<color=#ffd34c>食譜</color>。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"그것은 어쩌면 기적을 향한 실마리가 될지도 모르는 것.","JPN":"それはもしかしたら、奇跡への手がかりとなり得るかもしれないもの。","ENG":"Perhaps this, too, could be a clue to a Miracle.","TWN":"那或許是通往奇蹟的線索。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주여.","JPN":"主よ。","ENG":"Oh, Lord.","TWN":"主啊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어째서 저를 시험에 들게 하십니까…….","JPN":"私を試さないでください……","ENG":"Why do You lead me into temptation...?","TWN":"為什麼要考驗我……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어, 어째서…….","JPN":"ど、どうして……","ENG":"J-just why...?","TWN":"為，為什麼……"},"stage":{"bg":"CHOCOLAT_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어째서 그런…! 낯부끄러운 기억을 스스로 들추게 하시고 또 기록하게 하십니까……!","JPN":"どうしてこんな……！　恥ずかしい記憶を思い出し、また記録するようにするのですか……！","ENG":"WHY...?! Why must You make me dredge up this humiliating memory and write it down...?!","TWN":"為什麼要這樣……！讓我自己揭開那段丟臉的記憶，還要記錄下來……！"},"stage":{"bg":"CHOCOLAT_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어째서 그 파렴치한 기록을 당신의 비밀 서고에 영구히 보존하려 하십니까……!","JPN":"どうしてあの破廉恥な記録を、あなたの秘密書庫に永久保存しようとするのですか……！","ENG":"Why must these embarrassing records be preserved forever in the secret library...?!","TWN":"為什麼要將那份叫人丟臉的記錄永久保存在你的秘密書庫裡……！"},"stage":{"bg":"CHOCOLAT_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"평소처럼 냉철한 이성과 신앙심으로 기적의 보존을 행사할 것인지.","JPN":"いつもどおりに冷徹な理性と信仰で奇跡の保存を行うか。","ENG":"Will she continue to preserve the Miracle with her collected reason and faith?","TWN":"是否能像往常一樣，憑藉冷靜的理性和信仰來保存奇蹟。"},"stage":{"bg":"CHOCOLAT_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"사사로운 감정으로 자신이 목도한 기적을 부정하고, 자신의 손으로 말살할 것인지.","JPN":"私情で自分が目撃した奇跡を否定し、自分の手で抹殺するか。","ENG":"Or will she deny the Miracle she has witnessed out of personal feelings and destroy it herself?","TWN":"是否會因私情而否定自己目睹的奇蹟，並親手將其抹殺。"},"stage":{"bg":"CHOCOLAT_01","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"만약 그렇게 된다면 저는……!","JPN":"もしそうなったら、私は……！","ENG":"If this were to happen, then I...!","TWN":"如果那樣的話，我……！"},"stage":{"bg":"CHURCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……크읏!","JPN":"……くっ！","ENG":"...Kgh!","TWN":"……咳！"},"stage":{"bg":"CHURCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"시스터 넬슨이 제출한 경위서와 쇼콜라 무스 케이크의 레시피…….","JPN":"シスター・ネルソンが提出した経緯書とムースショコラのレシピ……","ENG":"I must destroy... the report Sister Nelson wrote and the chocolate mousse cake recipe...","TWN":"這是尼爾森修女提交的報告書和巧克力慕斯蛋糕的食譜……"},"stage":{"bg":"CHURCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"내 손으로 없애 버려야 해……. 아니, 애초부터 없었던 일로 만드는 거야…….","JPN":"私の手で処理しないと……いや、最初からなかったことにするのよ……","ENG":"I must do it... No, I must make it as if it never happened in the first place...","TWN":"我要親手消滅它……不，從一開始就不應讓它存在……"},"stage":{"bg":"CHURCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L44_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"무슨 수를 써서라도……!","JPN":"どんな手を使ってでも……！","ENG":"No matter what...!","TWN":"不管用什麼方法……！"},"stage":{"bg":"CHURCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"그 날. 새하얀 눈으로 뒤덮인 성야의 날.","JPN":"あの日。純白の雪で覆われた聖夜の日。","ENG":"That holy night, when the world was covered in pure white snow.","TWN":"那一天，被潔白的雪覆蓋的平安夜。"},"stage":{"bg":"CHURCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"그 거룩한 밤에 일어난 기적의 행방은 오롯이 이 젊은 사서의 손에 달려 있으니…….","JPN":"あの聖なる夜に起きた奇跡の行方は、まさにこの若い司書の手にかかっている……","ENG":"The Miracle that occurred on that holy night lies solely in the hands of this young librarian...","TWN":"那神聖之夜發生的奇蹟，全都掌握在這位年輕的管理員手中……"},"stage":{"bg":"CHURCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주여.","JPN":"主よ。","ENG":"Oh, Lord.","TWN":"主啊。"},"stage":{"bg":"CHURCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"부디 부덕한 저를 용서하여 주옵소서.","JPN":"どうか、不徳な私をお許しください。","ENG":"Please forgive my being unscrupulous.","TWN":"請你原諒我這個罪人。"},"stage":{"bg":"CHURCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……으음? 당신은?","JPN":"……うん？　あなたは？","ENG":"...Hmm? You?","TWN":"……呃嗯？你是……？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"뭐야, 안경. 뭐 하다 이제 오는 거야?","JPN":"なんだ、眼鏡ばばあ。遅かったね？","ENG":"Is that you, Specky? Where were you?","TWN":"什麼啊，四眼姊姊。你幹什麼去了，現在才來？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이상한 일이로군요, 시스터 루퍼.","JPN":"おかしなことですね、シスタールーパー。","ENG":"How strange, Sister Looper.","TWN":"真是奇怪，洛珀姊妹。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"사제 심사는 이미 끝났을 텐데요? 제 집무실에서 뭘 하고 있는 거죠?","JPN":"司祭審査はとっくに終わったはずです。私の執務室で何をしてるのですか？","ENG":"Your priest evaluation has already ended. So, what brings you to my office?","TWN":"考核應該已經結束了吧？你在我的辦公室裡做什麼？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"칫, 쪼잔하게. 좀 있으면 안 돼?","JPN":"なんだよ、ケチ。ちょっといるくらいいいじゃん。","ENG":"Ugh, such a cheapskate. Can't I be here?","TWN":"什麼啊，真小氣，再待一會兒不行嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"내 방에서는 집중이 잘 안된단 말이야.","JPN":"アタシの部屋じゃ集中できないんだよ。","ENG":"I can't concentrate in my room.","TWN":"我在自己的房間裡無法集中注意力。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"집중? 당신이 불경한 영상물 말고 집중할 일이 뭐가 있죠?","JPN":"集中？　あなたが不敬な映像以外に集中することなどあるのですか？","ENG":"Concentrate? What requires your focus other than watching blasphemous videos?","TWN":"集中？除了那些不潔的影片，你還有什麼好集中注意力的？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"우씨, 자꾸 말 시키지 마.","JPN":"ああ、もう話しかけないでよ。","ENG":"Hey, stop bothering me.","TWN":"哎呀，別老是跟我說話。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"지금 중요한 거 하고 있단 말이야.","JPN":"今大事なことやってるんだから。","ENG":"I'm doing something important right now.","TWN":"我現在在做很重要的事。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"앗, 무슨 짓이야 돌려줘!","JPN":"あっ、何するんだよ！　返せ！","ENG":"Huh? Hey! Give it back!","TWN":"啊，幹嘛，還給我！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이건… 수학 문제를 풀고 있었군요. 나눗셈인가요?","JPN":"これは……数学の問題ですね。割り算ですか？","ENG":"You were... solving mathematical problems. Divisions, I see.","TWN":"這是……在解數學題嗎？是除法嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"그래, 그게 뭐 어때서?","JPN":"そうだよ。それがどうしたの？","ENG":"Yeah, s-so what if I am?","TWN":"是啊，那又怎樣？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"의외로군요, 시스터 루퍼.","JPN":"意外ですね、シスター・ルーパー。","ENG":"I am perplexed, Sister Looper.","TWN":"真意外啊，洛珀姊妹。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"사제 심사가 끝나면, 더는 수학 같은 건 관심 없을 줄 알았는데요.","JPN":"司祭審査が終われば、もう数学なんて興味を持たないと思ったのですが。","ENG":"I thought you would no longer be interested in mathematics once your evaluation was over.","TWN":"祭司考核結束後，我以為你再也不會對數學感興趣了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"남이사 뭘 하든 뭔 상관이야?","JPN":"何をしたってあんたには関係ないでしょ？","ENG":"That's none of your business.","TWN":"關你什麼事？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"이제 네 도움 같은 거 없어도, 혼자서 완벽하게 풀 수 있다고.","JPN":"もうあんたが助けてくれなくても、ひとりで完璧に解けるから。","ENG":"I don't need your help anymore. I can handle this perfectly on my own.","TWN":"現在即使沒有你的幫助，我也能獨自完美地解題。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……완벽하게 전부 오답이로군요.","JPN":"……完璧に全部間違ってますね。","ENG":"...You got a perfect zero.","TWN":"……但你這完全都是錯誤答案啊。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"그래, 나 돌대가리다. 어쩔래? 뭐 보태준 거 있어?","JPN":"そうだよ、アタシはバカなんだよ。悪いか？","ENG":"Yeah, I'm dumb! What are you going to do about it? It's not like you helped.","TWN":"對，我就是個笨蛋。你能拿我怎麼樣？你又幫了什麼忙？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"뭐, 됐어.","JPN":"もう、やーめたっ。","ENG":"Eh, forget it.","TWN":"算了，沒事。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"역시 나한테… 착한 아이 같은 건 무리일지도…….","JPN":"やっぱりアタシに……いい子なんて無理かも……","ENG":"Just as I thought... maybe I can't make the nice list...","TWN":"果然對我來說……當個乖孩子還是太勉強了……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"착한 아이?","JPN":"いい子？","ENG":"Nice list?","TWN":"乖孩子？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"산타 할아범은 착한 아이한테만 선물을 준다면서?","JPN":"サンタのジジイはいい子じゃないとプレゼントをくれないんでしょ？","ENG":"Santa Claus gives presents to children on the nice list, no?","TWN":"聖誕老人不是只給乖孩子送禮物嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"난 산타 할아범도, 선물 같은 것도 필요 없지만… 그래도 산타 넬슨이랑 약속했거든.","JPN":"アタシはサンタのジジイも、プレゼントもいらないど……でもサンタクラウディアとは約束したんだ。","ENG":"I don't need Santa, or even a present, but... I made a promise with Santa Claudia.","TWN":"我不需要聖誕老人，也不需要禮物……不過我和聖誕克勞迪婭有約定。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"내년에도 같이 성탄제 열기로.","JPN":"来年も一緒に聖誕祭の行事をやろうって。","ENG":"To hold next year's Christmas party together.","TWN":"明年一起舉辦聖誕宴會。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"그러니까 내년에는 조금 더 착한 아이가 되면 어떨까 싶어서.","JPN":"だから、来年にはもっといい子になってみようと思ったんだ。","ENG":"So, I thought I'd be nicer next year.","TWN":"所以我在想，明年能不能變得更乖一點呢？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"후훗, 그새 철이 들어버렸군요, 시스터 루퍼.","JPN":"ふふっ、もう大人になってしまいましたね。シスター・ルーパー。","ENG":"Ha ha, you have matured, Sister Looper.","TWN":"呵呵，真是長大了呢，洛珀姊妹。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"마침내 조신한 시스터가 된 것 같아서 선배로서 기쁘답니다.","JPN":"ついに慎ましいシスターになったようで、先輩として嬉しいです。","ENG":"I am happy that you have finally become a respectable Sister.","TWN":"終於成為了一名端莊的修女，作為前輩我感到很高興。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"시끄러. 네 칭찬 같은 거 하나도 필요 없거든?","JPN":"うるさいよ。あんたに褒められても全然嬉しくないし。","ENG":"Shut it. Your compliments mean nothing to me, you know.","TWN":"閉嘴，我才不需要你的誇獎呢！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"계속 그렇게 놀릴 거면 저리 가.","JPN":"ずっとそうやってからかうなら、どっか行ってよ。","ENG":"Go away if you're going to keep teasing me.","TWN":"如果你繼續這樣捉弄我，就走開。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"잠깐만요. 그 종이는 설마……?","JPN":"待ってください。その紙は、まさか……？","ENG":"Hold on. That paper...","TWN":"等等，那張紙難道是……？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"뭐야, 왜 갑자기 벌레 씹은 얼굴이야?","JPN":"なんだよ、いきなり変な顔して。","ENG":"Huh? Why do you look disgusted all of a sudden?","TWN":"怎麼了，為什麼突然一臉鐵青？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신… 여기 연습장으로 쓰고 있는 서류들은 다 어디서 난 거죠?","JPN":"あなた……ノートに使っているこの書類は、どこから出したのですか？","ENG":"Sister... where did you get those pieces of paper you are using?","TWN":"你……在這裡當計算紙用的這些紙都是從哪裡來的？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"서류? 아, 이거……?","JPN":"書類？　あ、これ……？","ENG":"Paper? Oh, these...?","TWN":"紙？啊，這個……？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"그냥 여기 책상 위에 널브러져 있던 종이뭉치에서 대충 뜯어다 쓴 건데? 뭐 중요한 거야?","JPN":"この机の上にあった紙の山から適当に引っ張り出したんだけど。重要なもの？","ENG":"I just saw a bunch of paper lying around on the desk, so I took them. Were they important?","TWN":"只是隨便從桌子上的一堆紙裡撕下來用的，是什麼重要的文件嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"후, 후후후…….","JPN":"ふ、ふふふ……","ENG":"Ha, ha ha ha...","TWN":"呵，呵呵呵……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"뭐야? 기분 나쁘게 갑자기 왜 그렇게 웃어?","JPN":"何？　なんでいきなり笑うんだよ、気持ち悪い。","ENG":"Huh? Why are you laughing? You're starting to creep me out.","TWN":"幹嘛？為什麼突然笑得這麼詭異？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"제법이네요, 시스터 루퍼.","JPN":"やるではないですか、シスター・ルーパー。","ENG":"Impressive, Sister Looper.","TWN":"幹得不錯，洛珀姊妹。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"맨날 미운 짓만 골라서 하는 줄 알았는데, 가끔은 <color=#ffd34c>귀여운 짓</color>도 할 줄 아는군요.","JPN":"いつも変なことばかりやらかしていると思ったのですが、たまには<color=#ffd34c>可愛いこと</color>もやれるのですね。","ENG":"I always thought you deliberately chose to do things that upset me. But it seems you can be <color=#ffd34c>cute</color> sometimes too.","TWN":"我還以為你總是做些討人厭的事，沒想到你偶爾也會做些<color=#ffd34c>可愛的事</color>呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"귀여운 짓?","JPN":"可愛いこと？","ENG":"Cute?","TWN":"可愛的事？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"뭐, 좋습니다.","JPN":"まあ、いいでしょう。","ENG":"Very well.","TWN":"很好。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"배움에 목마른 이를 외면하지 않는 것 또한 주의 뜻.","JPN":"何かを学ぼうとする者から目を背けないのもまた主の意志。","ENG":"It is also the will of the Lord not to turn away those who wish to learn.","TWN":"不忽視渴望學習的人也是主的旨意。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"모르는 게 있다면 얼마든지 물어보세요. 특별히 가르쳐 드릴 테니.","JPN":"わからないことがあればいくらでも聞いてください。特別に教えてあげましょう。","ENG":"Feel free to ask anything you are curious about. I will be happy to teach you.","TWN":"如果有不懂的地方，儘管問我吧，我會單獨教你的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"……왠지 별로 안 내키는데.","JPN":"……なんかあまり気が乗らないんだけど。","ENG":"...Now I kind of don't want to.","TWN":"……總覺得你不太樂意啊。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"……이렇게 늦은 시간에 루퍼 자매님은 어디 간 거지?","JPN":"……こんな時間にシスター・シンディはどこに行ったのかしら？","ENG":"...Where could Sister Looper be at this late hour?","TWN":"……這麼晚了，洛珀姊妹去哪了？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"숙소에도 안 계계시고, 본당에도 안 계신다면 혼자 외출이라도 하신 건가?","JPN":"宿舎にもいないし、本堂にもいないならひとりでお出かけ？","ENG":"She's not in her dorms. If she's not at the Parish, did she go out alone?","TWN":"宿舍也不在，主堂也不在，難道是一個人外出了？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"음? 이 시간까지 집무실에 불이 켜져 있잖아?","JPN":"うん？　こんな遅い時間に執務室に明かりが？","ENG":"Mm? Why are the lights still on in the office this late at night?","TWN":"嗯？這麼晚了，辦公室的燈還亮著？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"……다음은 공평한 분할 문제로군요.","JPN":"……次は公平な分配の問題ですね。","ENG":"...Next is a fair division problem.","TWN":"……接下來是公平分配的問題了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하나의 케이크를 세 번의 칼질로 다섯 명이서 공평하게 나누려면 어떻게 해야 할까요?","JPN":"1つのケーキを3回切って、5人で公平に分け合うにはどうしたらいいのでしょうか。","ENG":"How can one cake be divided equally among five people by cutting only three times?","TWN":"如何用三刀將一個蛋糕公平地分給五個人？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"세 번의 칼질로 다섯 명이서 나눠야 한다고?","JPN":"3回切って5人に分け合わないといけないの？","ENG":"I need to make three cuts to share with five people?","TWN":"三刀要分給五個人？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"뭐야, 간단하잖아?","JPN":"なんだよ、簡単じゃん。","ENG":"That's easy.","TWN":"什麼呀，比我想的要簡單嘛！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"간단하다고요?","JPN":"簡単ですか？","ENG":"Easy?","TWN":"很簡單嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"그래, 먼저 두 번의 칼질로 케이크를 네 조각으로 만든 다음…….","JPN":"そうだよ。まずはケーキを2回切って4つにしてから……","ENG":"Yeah. I first cut the cake into four slices with two cuts...","TWN":"好，先用兩刀把蛋糕切成四塊，然後……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"남은 한 번의 칼질로 한 명을 끝장내 버리면, 넷이서 네 조각을 공평하게 나눌 수 있잖아?","JPN":"残りの1回で1人を始末すると、4人で4つ公平に食べられるじゃん。","ENG":"Then, I cut down one person, so there are four slices for four people.","TWN":"如果用最後一刀解決一個人，我們四個人就可以公平地分成四塊了，不是嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L39_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"오답입니다. 그런 폭력적인 방식은 용인되지 않아요.","JPN":"ハズレです。そんな暴力的なやり方は認められません。","ENG":"That is incorrect. Such violence is unacceptable.","TWN":"回答錯誤，那種暴力的方式是不能容忍的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"뭐? 틀렸다고? 그럼 답이 뭔데?","JPN":"はあ？　ハズレ？　じゃあ、正解はなんだよ？","ENG":"What? That's not it? Then what's the answer?","TWN":"什麼？錯了嗎？那答案是什麼？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"자, 잘 들으세요, 시스터 루퍼.","JPN":"さあ、よく聞きなさい。シスター・ルーパー。","ENG":"Now, listen carefully, Sister Looper.","TWN":"來，聽好了，洛珀姊妹。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"자고로 이 분할 문제의 기원은 창세기 시절 아브라함과 롯의 갈등으로부터 유래됐죠.","JPN":"この分配問題の起源は、創世記にアブラハムとロトの葛藤から由来したものです。","ENG":"The origin of this division problem traces back to Abraham and Lot's conflict in the Book of Genesis.","TWN":"說到這個分裂問題的起源，可以追溯到創世紀時期亞伯拉罕和羅得的衝突。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아브라함과 사촌인 롯은 비좁은 목초지를 두고 갈등하게 되는데…….","JPN":"アブラハムと甥のロトは狭い牧草地をめぐって葛藤することになったのですが……","ENG":"Abraham and his cousin, Lot, were fighting over a narrow pasture–","TWN":"亞伯拉罕和他的姪子羅得因為牧場過於狹窄而產生了衝突……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"에휴, 이 언니 또 시작이네.","JPN":"ああ、また始まったよ。","ENG":"Ugh, there she goes again.","TWN":"哎，你又開始了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L49_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"그런 지겨운 성경 말씀은 아무래도 좋으니까, 답이나 알려달라고.","JPN":"そんな退屈な聖書の話はどうでもいいから、答えを教えてよ。","ENG":"I don't care what the Bible says, so just tell me the answer.","TWN":"那種枯燥的聖經故事就說到這吧，直接告訴我答案啦。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"걱정마세요, 전부 필요한 과정이니까.","JPN":"焦らないでください、この過程も全部必要なんです。","ENG":"Rest assured, this is all a necessary process.","TWN":"不行，這都是必須要知道的內容。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"……후훗.","JPN":"……ふふっ。","ENG":"...Haha.","TWN":"……呵呵。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"이렇게 늦은 시간까지 두 자매님께서 학업에 열중하고 계시다니…….","JPN":"こんなに遅い時間まで2人で勉強に熱中しているなんて……","ENG":"I didn't know the two of them would be so focused on learning this late in the night...","TWN":"這麼晚了，兩位姊妹還在專心學習……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"두 자매님의 사이가 좋아져서 참 다행이야.","JPN":"2人が仲良くなってよかった。","ENG":"I'm so glad that they have gotten closer with each other.","TWN":"看你們關係變得這麼好，真是太好了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"음? 그러고 보니…….","JPN":"うん？　そういえば……","ENG":"Mm? Come to think of it...","TWN":"嗯？話說回來……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"자네가 소원을 빌지 않았나?","JPN":"君が願っただろう？","ENG":"You made a wish, didn't you?","TWN":"你不是許了願嗎？"},"stage":{"bg":"CHOCOLAT_01","bgm":"THEMA_XMAS","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CLOUDIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L13_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"오늘 밤, 두 시스터의 사이가 가까워질 바란다고.","JPN":"今夜、2人のシスターが仲良くなりますようにと。","ENG":"You wished that tonight, the two Sisters would become closer.","TWN":"希望今晚兩位姊妹的關係能更親近一些。"},"stage":{"bg":"CHOCOLAT_01","bgm":"THEMA_XMAS","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CLOUDIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"CAKE_CHOCOLAT_NPC_BROTHER","text":{"KOREA":"사람과 사람이 가까워지려면 몇번의 기적이 겹치고 겹쳐야 가능한 법이거든.","JPN":"人と人が絆を深めるためには、奇跡が何度も重ならなくてはいけないのだ。","ENG":"In order to make two people become closer, miracles must occur over and over again.","TWN":"人與人之間要想親近，需要幾次奇蹟重疊起來才有可能。"},"stage":{"bg":"CHOCOLAT_01","bgm":"THEMA_XMAS","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CLOUDIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BIBLIDES_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그렇군요, 쇼콜라 형제님.","JPN":"そうだったのですね、ブラザー・ショコラ。","ENG":"I see, Brother Chocolat.","TWN":"原來如此，巧克力弟兄。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"저 두 사람의 화목한 모습이야 말로, 당신이 선물한 성탄절의 기적이었네요.","JPN":"あの2人の穏やかな姿こそ、あなたがプレゼントしてくれたクリスマスの奇跡。","ENG":"The true Christmas miracle was your gift of seeing those two become closer.","TWN":"那兩個人和睦的樣子，正是你送給她們的聖誕奇蹟啊。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"후후, 그래요. 이 또한 자비로운 주님께서 베푸신 은총이겠죠.","JPN":"ふふ、そうです。これもまた慈しみ深い神がお与えになった恵でしょう。","ENG":"Haha, yes. This, too, must be a blessing from the merciful Lord.","TWN":"呵呵，是啊，這也是仁慈的主賜予的恩典吧。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"감사합니다. 주님. 올해도 행복한 성탄절을 보낼 수 있게 해주셔서.","JPN":"ありがとうございます、神様。今年も幸せな聖誕祭を迎えることができました。","ENG":"Thank you, Lord. For allowing us to celebrate a wonderful Christmas this year.","TWN":"感謝主，今年度過一個幸福的聖誕節。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그리고 내년에도…….","JPN":"そして、来年も……","ENG":"And next year too...","TWN":"還有明年也是……"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"부디, 모두가 행복한 성탄절이 되기를.","JPN":"どうか、すべての人が幸せな聖誕祭を迎えられますように。","ENG":"I hope everyone has a Merry Christmas.","TWN":"祝大家聖誕節快樂。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"subtitle","speaker":null,"text":{"KOREA":"제9호 기적심의회, 성무 경위 보고서\\n성무 코드 <color=#ffd34c>X12MAS25</color>","JPN":"第9号奇跡審議会、聖務経緯報告書\\n聖務コード<color=#ffd34c>X12MAS25</color>","ENG":"Miracle Investigation Council 9, Sacred Mission Report\\nSacred Mission Code <color=#ffd34c>X12MAS25</color>","TWN":"第九奇蹟議會,聖務報告書\\n聖務代碼 <color=#ffd34c>X12MAS25</color>"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"subtitle","speaker":null,"text":{"KOREA":"본 보고서는 시성성의 기적 심사에 대한 이의제기를 위해 작성되었습니다.","JPN":"この報告書は列聖省の奇跡審査に異議を申し立てるために作成されました。","ENG":"This report has been prepared to challenge the Dicastery for the Causes' evaluation of the Miracle.","TWN":"本報告是對封聖部委員會的奇蹟審查提出的異議而撰寫的。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"subtitle","speaker":null,"text":{"KOREA":"시성상은 집행 사제 클로디아 넬슨이 제조한 케이크가 기적이라고 주장하고 있으나 이는 사실과 다름을 보고합니다.","JPN":"列聖省は執行司祭クラウディア・ネルソンが製造した\\nケーキが奇跡であると主張していますが、\\nこれは事実ではありませんのでご報告します。","ENG":"The Dicastery for the Causes claims Inquisitorial Priest Claudia Nelson's cake to be a Miracle,\\nbut this is far from the truth.","TWN":"封聖部委員會聲稱治理祭司克勞迪婭·尼爾森製作的蛋糕是奇蹟，但事實並非如此，特此報告。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"subtitle","speaker":null,"text":{"KOREA":"첫째, 케이크의 재료가 된 솔로카오 초콜릿 제공자의 증언에 따르면\\n솔로카오 초콜릿은 특수한 공정을 거쳐 원래부터 인체에 무해한 것으로 판명되었습니다. 즉, 기적이 아닙니다.","JPN":"その一、ケーキの材料になったソロカオチョコレートを\\n提供した者の証言によりますと、\\nソロカオチョコレートは特殊な工程を経ており、\\n元々人体に無害であると判明されました。\\nつまり、奇跡ではありません。","ENG":"First, according to the testimony of the supplier of the Solocao chocolate,\\nthe chocolate underwent a special process and was found to be harmless to the human body from the start.\\nTherefore, it cannot be classified as a Miracle.","TWN":"首先，根據提供獨株巧克力的供應商的證詞，\\n獨株巧克力經過特殊加工處理，原本就是對人體無害的。由此說明，這並不是奇蹟。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"subtitle","speaker":null,"text":{"KOREA":"둘째, 케이크가 독립적 자아 및 높은 지성을 가졌다는 증언은 현장의 증인 전원이 증언을 번복하여 효력을 상실하였습니다.","JPN":"その二、ケーキが独立的な自我および高い知性を保有したという証言は、\\n現場の全証人が\\n証言を覆しましたので有効性を喪失しました。","ENG":"Second, the testimonies regarding the cake's sentience and high intelligence were retracted\\nby all the witnesses at the scene, rendering them invalid.","TWN":"其次，關於蛋糕具有獨立自我和高智商的證詞，由於現場所有證人皆撤回他們的證詞，因此這些證詞已失去效力。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"subtitle","speaker":null,"text":{"KOREA":"또한 그중 다수가 기억 소실을 겪었다고 증언하였습니다. 즉, 기적이 아닙니다.","JPN":"また、その中の多数が記憶喪失を経験していると証言しました。\\nつまり、奇跡ではありません。","ENG":"Furthermore, many of the witnesses reported experiencing memory loss. Hence, not a Miracle.","TWN":"此外，其中多數證人聲稱期間經歷記憶喪失。進一步證明，這並不是奇蹟。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"subtitle","speaker":null,"text":{"KOREA":"셋째, 별도 첨부한 문서는 클로디아 넬슨에게 지시한 케이크의 레시피입니다.","JPN":"その三、別途添付した文書はクラウディア・ネルソンが提供したケーキのレシピです。","ENG":"Third, the attached document is the recipe for the cake that was instructed by Claudia Nelson.","TWN":"第三，附上的夾帶檔案是克勞迪婭·尼爾森使用的蛋糕食譜。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"subtitle","speaker":null,"text":{"KOREA":"그러나 해당 문서는 일반적인 케이크 레시피와는 달리\\n케이크를 공평하게 나누는 법에 관해 서술하고 있을 뿐 그 진정한 의미를 짐작하기 어렵습니다.","JPN":"ですが、該当の文書は一般的なケーキのレシピとは違い、\\nケーキを公平に分ける方法について述べられているだけで、\\nその真の意味を推察することはできません。","ENG":"However, unlike typical cake recipes, this document merely describes how to fairly divide the cake,\\nmaking its true meaning difficult to ascertain.","TWN":"然而，該檔與普通蛋糕食譜不同，\\n僅描述該如何公平地分配蛋糕，難以推測其真正含義。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"subtitle","speaker":null,"text":{"KOREA":"클로디아 넬슨 본인 역시 레시피에 대해 어떠한 기억도 떠올리지 못하고 있으며\\n이는 일시적인 환각 증세로 추정됩니다. 즉, 기적이 아닙니다.","JPN":"クラウディア・ネルソンはこのレシピについてまったく記憶しておらず、\\nこれは一時的な幻覚と推定されます。\\nつまり、奇跡ではありません。","ENG":"Claudia Nelson herself has no recollection of this recipe,\\nwhich is believed to be the result of a temporary hallucinatory state.\\nTherefore, not a Miracle.","TWN":"克勞迪婭·尼爾森本人無法回憶起這份食譜的任何內容，\\n被認為是暫時性的幻覺症狀。也就是說，這並不是奇蹟。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"subtitle","speaker":null,"text":{"KOREA":"이에 따라 심의회는 시성성의 주장과 달리\\n본 사건이 기적과 무관한 단순한 침식현상 및 이면세계 식재료에 의한 환각이라고 주장하는바.","JPN":"これにより審議会は、列聖省の主張に反して本件が奇跡とは関係のない、\\n単なる侵食現象および裏世界食材による幻覚と主張します。","ENG":"Consequently, the Investigation Council asserts that, contrary to the Dicastery for the Causes' claims,\\nthis incident is unrelated to a Miracle and is instead a simple case of the Counterside Effect\\nand hallucinations induced by the Counterside ingredients.","TWN":"因此，議會與封聖部委員會的主張相反，\\n本事件並非奇蹟，而是簡單的侵蝕現象以及異界食材引起的幻覺"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"subtitle","speaker":null,"text":{"KOREA":"본 사건의 특수성으로 인해\\n사건과 관련된 증언 및 증거는 그 진위여부를 가리는 것이 매우 소모적이며 비생산적이라는 것을 보고합니다.","JPN":"本件の特殊性により、\\n事件と関係がある証言および証拠はその真偽の程を確かめることにおいて、\\n相当に非効率的かつ非生産的であることをご報告します。","ENG":"Given the unique nature of this incident, further investigation into the veracity of the testimonies\\nand evidence would be highly resource-draining and unproductive.","TWN":"由於本事件的特殊性，\\n議會認為辨別與此事件相關的證詞及證據的真偽是非常消耗精力且無益的。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"subtitle","speaker":null,"text":{"KOREA":"작성자 — 비블리데 루체","JPN":"作成者 - ビブリデ・ルーチェ","ENG":"Author — Biblide Luce","TWN":"撰寫人-布莉黛·露契"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};